firmware_template.source:
#include "ads1115.h"
#include <Wire.h>
static Adafruit_ADS1115 ads;
static int16_t _raw[4] = {0};
static unsigned long _last = 0;
void ads1115_setup() {
  Wire.begin();
  if (!ads.begin(0x48)) { Serial.println("[ads1115] Init failed!"); return; }
  ads.setGain(GAIN_TWOTHIRDS);
  Serial.println("[ads1115] OK 16-bit");
}
void ads1115_loop() {
  if (millis()-_last < 200) return;
  _last = millis();
  for (uint8_t i = 0; i < 4; i++) {
    _raw[i] = ads.readADC_SingleEnded(i);
  }
}
int16_t ads1115_read_channel(uint8_t ch) { return (ch < 4) ? _raw[ch] : 0; }
float ads1115_read_voltage(uint8_t ch) { return (ch < 4) ? ads.computeVolts(_raw[ch]) : 0.0f; }
